mapper.select:
SELECT , u.username
FROM engineer e
LEFT JOIN sys_user u ON u.id = e.user_id AND u.deleted = 0

    e.deleted = 0

        AND (e.name LIKE CONCAT('%', #{query.keyword}, '%')
          OR e.employee_no LIKE CONCAT('%', #{query.keyword}, '%')
          OR e.phone LIKE CONCAT('%', #{query.keyword}, '%'))


        AND e.status = #{query.status}


        AND e.region = #{query.region}


        AND e.user_id = #{query.userId}


        AND EXISTS (
            SELECT 1 FROM engineer_skill s
            WHERE s.engineer_id = e.id
              AND s.skill_tag = #{query.skillTag}
              AND s.deleted = 0

                AND s.level = #{query.skillLevel}

        )


ORDER BY e.create_time DESC

SELECT DISTINCT , u.username FROM engineer e LEFT JOIN sys_user u ON u.id = e.user_id AND u.deleted = 0
e.deleted = 0 AND e.status = #{status} 'ACTIVE'
AND e.region = #{region}
AND EXISTS ( SELECT 1 FROM engineer_skill s WHERE s.engineer_id = e.id AND s.deleted = 0 AND s.skill_tag IN
#{tag}
)
ORDER BY e.create_time DESC

SELECT e.id AS engineerId, e.name AS engineerName, e.region AS region, DATE(es.start_time) AS date, COUNT(es.id) AS taskCount FROM engineer e LEFT JOIN engineer_schedule es ON es.engineer_id = e.id AND es.deleted = 0 AND es.schedule_type = 'TASK' AND es.start_time < #{endTime} AND es.end_time > #{startTime}
e.deleted = 0 AND e.status = 'ACTIVE'
AND e.region = #{region}
AND e.id IN
#{eid}
GROUP BY e.id, e.name, e.region, DATE(es.start_time) HAVING taskCount > 0 ORDER BY e.id, date

SELECT COUNT(1) FROM engineer
WHERE user_id = #{userId} AND deleted = 0

    AND id != #{excludeId}
